import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is TDEE?", a: "TDEE means Total Daily Energy Expenditure. It is the estimated number of calories you burn per day including activity." },
  { q: "How do you calculate TDEE?", a: "Calculate BMR first, then multiply by an activity factor that reflects your daily movement and exercise." },
  { q: "What is the difference between TDEE and BMR?", a: "BMR is calories burned at rest. TDEE includes BMR plus activity, exercise, and daily movement." },
  { q: "How do you use TDEE to lose weight?", a: "Eat below TDEE to create a calorie deficit. A 500 calorie daily deficit is a common moderate starting point." },
  { q: "How accurate are TDEE calculators?", a: "They are estimates. Track body weight and intake for a few weeks, then adjust based on real results." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const activity: Record<string, [number, string]> = { Sedentary: [1.2, "Little exercise"], "Lightly Active": [1.375, "Light exercise 1-3 days"], "Moderately Active": [1.55, "Moderate exercise 3-5 days"], "Very Active": [1.725, "Hard exercise 6-7 days"], "Extremely Active": [1.9, "Athlete or physical job"] };
function mifflin(g: string, age: number, h: number, w: number) { return 10 * w + 6.25 * h - 5 * age + (g === "Male" ? 5 : -161); }
function harris(g: string, age: number, h: number, w: number) { return g === "Male" ? 88.362 + 13.397 * w + 4.799 * h - 5.677 * age : 447.593 + 9.247 * w + 3.098 * h - 4.33 * age; }

export default function TDEECalculator() {
  const [age, setAge] = useState(30), [gender, setGender] = useState("Male"), [height, setHeight] = useState(175), [weight, setWeight] = useState(77), [level, setLevel] = useState("Moderately Active");
  const result = useMemo(() => {
    const m = mifflin(gender, age, height, weight) * activity[level][0];
    const hb = harris(gender, age, height, weight) * activity[level][0];
    const tdee = m;
    return { m, hb, tdee };
  }, [age, gender, height, weight, level]);
  const refBmr = mifflin("Male", 30, 178, 77);
  const rows = Object.entries(activity).map(([name, [factor, desc]]) => [name, desc, refBmr * factor, refBmr * factor - 500, refBmr * factor + 300]);
  return (
    <>
      <SEOHead title="Free TDEE Calculator Online - Calculate Total Daily Energy Expenditure Instantly | CalcHive" description="Free online TDEE calculator. Calculate your total daily energy expenditure and calorie targets for weight loss, maintenance and muscle gain instantly. 100% free, no signup required." canonical="/tdee-calculator" keywords="free TDEE calculator, total daily energy expenditure calculator free online, maintenance calories calculator free, calorie calculator TDEE free, how many calories do I burn free calculator" category="Health Calculators" breadcrumbName="Free TDEE Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free TDEE Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate maintenance calories and targets for weight loss or muscle gain.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (cm)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (kg)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Activity level</label><select value={level} onChange={(e) => setLevel(e.target.value)} className={inputClass}>{Object.keys(activity).map((x) => <option key={x}>{x}</option>)}</select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Maintenance Calories</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.tdee)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Weight loss</p><p className="text-lg font-extrabold">{Math.round(result.tdee - 500)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Aggressive loss</p><p className="text-lg font-extrabold">{Math.round(result.tdee - 1000)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Muscle gain</p><p className="text-lg font-extrabold">{Math.round(result.tdee + 300)}</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your TDEE for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator estimates BMR with Mifflin-St Jeor and Harris-Benedict, then multiplies by an activity factor.</p><h2 className="text-2xl font-bold">How to Use TDEE to Lose Weight or Build Muscle</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">TDEE by Activity Level - 170lb 30yr Old Male</caption><thead className="bg-muted/60"><tr>{["Activity Level", "Description", "TDEE Calories", "Weight Loss Target", "Muscle Gain Target"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={String(r[0])}><td className="py-2.5 px-3 font-semibold">{r[0]}</td><td className="py-2.5 px-3">{r[1]}</td><td className="py-2.5 px-3">{Math.round(Number(r[2]))}</td><td className="py-2.5 px-3">{Math.round(Number(r[3]))}</td><td className="py-2.5 px-3">{Math.round(Number(r[4]))}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Total Daily Energy Expenditure Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/tdee-calculator" headingLevel="h3" /></main>
    </>
  );
}


